import React, { useEffect, useState } from 'react';
import ProductForm from '../components/ProductForm';
import ProductList from '../components/ProductList';
import StockMovementForm from '../components/StockMovementForm';
import axios from 'axios';

const Products = () => {
    const [products, setProducts] = useState([]);
    const [movements, setMovements] = useState([]);
    const [selectedProduct, setSelectedProduct] = useState(null);
    const [productNames, setProductNames] = useState({});

    // Função para buscar produtos
    const fetchProducts = async () => {
        try {
            const response = await axios.get('http://127.0.0.1:8000/api/produtos/');
            setProducts(response.data);
            const namesMapping = response.data.reduce((acc, product) => {
                acc[product.id] = product.nome;
                return acc;
            }, {});
            setProductNames(namesMapping);
        } catch (error) {
            console.error("Erro ao buscar produtos:", error);
        }
    };

    // Função para buscar movimentações
    const fetchMovements = async () => {
        try {
            const response = await axios.get('http://127.0.0.1:8000/api/movimentacoes/');
            setMovements(response.data);
        } catch (error) {
            console.error("Erro ao buscar movimentações:", error);
        }
    };

    // Função para editar um produto
    const handleEdit = (product) => {
        setSelectedProduct(product); // Define o produto selecionado para edição
    };

    // Função para atualizar a quantidade do produto após movimentação
    const updateProductQuantity = (productId, tipoMovimentacao, quantidade) => {
        setProducts((prevProducts) => {
            const updatedProducts = prevProducts.map((product) => {
                if (product.id === productId) {
                    const newQuantity = tipoMovimentacao === 'entrada'
                        ? product.quantidade + quantidade
                        : product.quantidade - quantidade;
                    return { ...product, quantidade: newQuantity };
                }
                return product;
            });
            return updatedProducts;
        });
    };

    useEffect(() => {
        fetchProducts(); // Chama a função ao montar o componente
        fetchMovements(); // Chama a função ao montar o componente
    }, []);

    return (
        <div>
            <h2>Lista de Produtos</h2>
            <ProductForm refreshProducts={fetchProducts} selectedProduct={selectedProduct} />
            <ProductList products={products} onEdit={handleEdit} onDelete={handleDelete} />
            <h2>Registrar Movimentação de Estoque</h2>
            <StockMovementForm 
                refreshMovements={fetchMovements} 
                updateProductQuantity={updateProductQuantity} 
                refreshProducts={fetchProducts} // Passa a função para atualizar produtos
            />
            <h2>Movimentações de Estoque</h2>
            <div>
                {movements.map((movement) => (
                    <div key={movement.id} style={{ border: '1px solid #ccc', margin: '10px', padding: '10px' }}>
                        <h3>Produto: {productNames[movement.produto]}</h3>
                        <p><strong>Tipo:</strong> {movement.tipo_movimentacao}</p>
                        <p><strong>Quantidade:</strong> {movement.quantidade}</p>
                        <p><strong>Motivo:</strong> {movement.motivo}</p>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default Products;
